function createBaskPatrols()
	bask_patrol_fleets = {}
	local patrol_ships = {}
	local patrol_list = {
		"Kraylor01",
		"Kraylor02",
		"Exuari01",
		"Exuari02",		
		"TSN01",		
		"Ghosts01",		
		"Ktlitans01",		
		"Arlenians01",
		"Ghosts02",
		"CUF01",
		"Arlenians02",
		"Ktlitans02",
		"Ghosts03",
		"Ktlitans03",
		"CUF02",
		"TSN02",
		"Independent01",
		"Independent02",
		"USN01",
		"Independent03",
		"Independent04",
		"Independent05",
		"USN02",
		"Human01",
		"Arlenians03",
		"Independent06",
	}
	for i, patrol_name in ipairs(patrol_list) do
		local patrol = createBaskPatrol(patrol_name)
		if patrol ~= nil then
			table.insert(bask_patrol_fleets,{name=patrol_name,ships=patrol})
			for j, ship in ipairs(patrol) do
				table.insert(patrol_ships,ship)
			end
		end
	end
	return patrol_ships
end
